// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

/**
 * Thread-local bridge for reporting actual runtime outcomes back to planner-level bandit feedback.
 */
public final class JoinEngineRuntimeFeedback {

	private static final ThreadLocal<PendingFeedback> CURRENT = new ThreadLocal<>();

	private JoinEngineRuntimeFeedback() {
	}

	static void registerSelection(BanditPolicy bandit, String regionFingerprint, String planner,
			double fallbackReward) {
		PendingFeedback previous = CURRENT.get();
		if (previous != null && !previous.reported) {
			previous.reportFallback();
		}
		CURRENT.set(new PendingFeedback(bandit, regionFingerprint, planner, fallbackReward));
	}

	public static boolean reportSelectedPlanElapsedMillis(double elapsedMillis) {
		PendingFeedback pending = CURRENT.get();
		if (pending == null) {
			return false;
		}
		pending.reportElapsed(elapsedMillis);
		CURRENT.remove();
		return true;
	}

	public static void clearCurrentThread() {
		CURRENT.remove();
	}

	private static final class PendingFeedback {

		private final BanditPolicy bandit;
		private final String regionFingerprint;
		private final String planner;
		private final double fallbackReward;
		private boolean reported;

		private PendingFeedback(BanditPolicy bandit, String regionFingerprint, String planner, double fallbackReward) {
			this.bandit = bandit == null ? BanditPolicy.noop() : bandit;
			this.regionFingerprint = regionFingerprint;
			this.planner = planner;
			this.fallbackReward = fallbackReward;
		}

		private void reportElapsed(double elapsedMillis) {
			if (reported) {
				return;
			}
			double safeElapsedMillis = sanitizeElapsed(elapsedMillis);
			bandit.reportOutcome(regionFingerprint, planner, -safeElapsedMillis);
			reported = true;
		}

		private void reportFallback() {
			if (reported) {
				return;
			}
			double safeFallback = Double.isFinite(fallbackReward) ? fallbackReward : 0.0d;
			bandit.reportOutcome(regionFingerprint, planner, safeFallback);
			reported = true;
		}

		private double sanitizeElapsed(double elapsedMillis) {
			if (!Double.isFinite(elapsedMillis) || elapsedMillis <= 0.0d) {
				return 1.0d;
			}
			return elapsedMillis;
		}
	}
}
